                <svg viewBox="0 0 16 16" className="w-3 h-3 fill-[#ed621d]"><path d="M8 2l1.4 4.6L14 8l-4.6 1.4L8 14l-1.4-4.6L2 8l4.6-1.4z"/></svg>
